// Bundled hospital + doctor catalog (reference data).
// Generated by server/generate-catalog.js. Imported directly so browsing and
// search work instantly, with no backend round-trip.
import data from "./catalog.json";

export const hospitals = data.hospitals;
export const doctors = data.doctors;

const uniq = (arr) => [...new Set(arr.filter(Boolean))];

export const specialities = uniq(doctors.map((d) => d.speciality)).sort();
export const locations = uniq(hospitals.map((h) => h.location)).sort();
